package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl.bijdrage.patronaal.pensioenpijler2;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.PensioenPijler2BonusBijdrage;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.pensioenpijler2.PensioenPijler2TypeBijdrage;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.VrijstelPens2;
import com.google.common.collect.ImmutableList;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.List;

public class PensioenPijler2BonusBijdrageDmfappl implements PensioenPijler2BonusBijdrage {
    private static final List<VrijstelPens2> VRIJSTELLINGEN_MET_BONUS_DMFAPPL = ImmutableList.of(VrijstelPens2.BONUSBIJDRAGE, VrijstelPens2.BONUSBIJDRAGE2);
    private final ConstantManager constantManager;
    private final VrijstelPens2 vrijstellingTweedePensioenpijler;
    private final RekenTijd rekenTijd;
    private final LocalDate gegevensDatum;

    public PensioenPijler2BonusBijdrageDmfappl(
            ConstantManager constantManager, VrijstelPens2 vrijstellingTweedePensioenpijler, RekenTijd rekenTijd, LocalDate gegevensDatum) {
        this.constantManager = constantManager;
        this.vrijstellingTweedePensioenpijler = vrijstellingTweedePensioenpijler;
        this.rekenTijd = rekenTijd;
        this.gegevensDatum = gegevensDatum;
    }

    public boolean heeftBonusBijdrageTweedePensioenPijler() {
        boolean notTypeBijdrageAntwerpen = isNotTypeBijdrageAntwerpen();
        boolean vrijstellingMetBonus = isVrijstellingMetBonus();
        boolean heeftPositieveBonus = heeftPositieveBonus();
        return notTypeBijdrageAntwerpen && vrijstellingMetBonus && heeftPositieveBonus;
    }

    public boolean isVrijstellingMetBonus() {
        return VRIJSTELLINGEN_MET_BONUS_DMFAPPL.contains(vrijstellingTweedePensioenpijler);
    }

    private boolean isNotTypeBijdrageAntwerpen() {
        Constant typeBijdragePens2 = constantManager.getActualConstant(Konstanten.KST_TYPE_BIJDRAGE_PENS2, rekenTijd, gegevensDatum);
        Integer typeBijdrage = typeBijdragePens2.getInteger();
        return !PensioenPijler2TypeBijdrage.isAntwerpen(typeBijdrage);
    }

    private boolean heeftPositieveBonus() {
        Constant bijdrageBonusPens2Constant = getBijdrageBonusPens2Constant();
        BigDecimal bijdrageBonusPens2 = bijdrageBonusPens2Constant.getProcentFactor();
        return bijdrageBonusPens2.signum() > 0;
    }

    private Constant getBijdrageBonusPens2Constant() {
        Konstanten constant = getKonstanteBijdragePens2B();
        return constantManager.getActualConstant(constant, rekenTijd, gegevensDatum);
    }

    public Konstanten getKonstanteBijdragePens2B() {
        if (vrijstellingTweedePensioenpijler == VrijstelPens2.BONUSBIJDRAGE) {
            return Konstanten.KST_BIJDRAGE_PENS2B;
        } else {
            return Konstanten.KST_BIJDRAGE_PENS2B_PERC2;
        }
    }
}
